  (() => {
    // --- HÀM HELPER: CHUẨN HÓA TEXT ---
    // Chuyển "Nguyễn Châu Giang" -> "NGUYEN CHAU GIANG"
    function normalizeText(str) {
      if (!str) return "";
      str = str.replace(/à|á|ạ|ả|ã|â|ầ|ấ|ậ|ẩ|ẫ|ă|ằ|ắ|ặ|ẳ|ẵ/g, "a");
      str = str.replace(/è|é|ẹ|ẻ|ẽ|ê|ề|ế|ệ|ể|ễ/g, "e");
      str = str.replace(/ì|í|ị|ỉ|ĩ/g, "i");
      str = str.replace(/ò|ó|ọ|ỏ|õ|ô|ồ|ố|ộ|ổ|ỗ|ơ|ờ|ớ|ợ|ở|ỡ/g, "o");
      str = str.replace(/ù|ú|ụ|ủ|ũ|ư|ừ|ứ|ự|ử|ữ/g, "u");
      str = str.replace(/ỳ|ý|ỵ|ỷ|ỹ/g, "y");
      str = str.replace(/đ/g, "d");
      str = str.replace(/À|Á|Ạ|Ả|Ã|Â|Ầ|Ấ|Ậ|Ẩ|Ẫ|Ă|Ằ|Ắ|Ặ|Ẳ|Ẵ/g, "A");
      str = str.replace(/È|É|Ẹ|Ẻ|Ẽ|Ê|Ề|Ế|Ệ|Ể|Ễ/g, "E");
      str = str.replace(/Ì|Í|Ị|Ỉ|Ĩ/g, "I");
      str = str.replace(/Ò|Ó|Ọ|Ỏ|Õ|Ô|Ồ|Ố|Ộ|Ổ|Ỗ|Ơ|Ờ|Ớ|Ợ|Ở|Ỡ/g, "O");
      str = str.replace(/Ù|Ú|Ụ|Ủ|Ũ|Ư|Ừ|Ứ|Ự|Ử|Ữ/g, "U");
      str = str.replace(/Ỳ|Ý|Ỵ|Ỷ|Ỹ/g, "Y");
      str = str.replace(/Đ/g, "D");
      return str.normalize("NFD").replace(/[\u0000-\u0019]/g, "").toUpperCase().trim();
    }

    // 1. LẤY DỮ LIỆU ĐẦU VÀO
    const vector = $json.query_vector || $json.vector; 
    let aiJson = {};
    try {
      if ($('message refined') && $('message refined').item) {
          aiJson = $('message refined').item.json.parsed_json || 
                   JSON.parse($('message refined').item.json.output);
      }
    } catch (e) { aiJson = {}; }

    // 2. KHỞI TẠO FILTER
    let mustConditions = [];

    // --- A. Lọc theo Tên (LOGIC MỚI: BAO VÂY CẢ CÓ DẤU & KHÔNG DẤU) ---
    if (aiJson.filter_candidate_name) {
      const originalName = aiJson.filter_candidate_name.trim(); // "Nguyễn Châu Giang"
      const normalizedName = normalizeText(originalName);       // "NGUYEN CHAU GIANG"

      // Tạo điều kiện OR (Should): Chỉ cần khớp 1 trong 2 là lấy
      let nameConditions = [];

      // 1. Tìm chính xác những gì user nhập (Có dấu/Viết thường...)
      nameConditions.push({
        "key": "candidate_name",
        "match": { "text": originalName } 
      });

      // 2. Tìm phiên bản chuẩn hóa (Không dấu, In hoa)
      // (Chỉ thêm nếu nó khác bản gốc để tránh trùng lặp query)
      if (normalizedName !== originalName.toUpperCase()) {
         nameConditions.push({
            "key": "candidate_name",
            "match": { "text": normalizedName }
         });
      }

      // Đẩy cụm OR này vào trong MUST
      // Nghĩa là: (Tên == "Nguyễn..." HOẶC Tên == "NGUYEN...") VÀ (Các đk khác...)
      mustConditions.push({
        "should": nameConditions
      });
    }

    // --- B. Các bộ lọc khác (Giữ nguyên) ---
    if (aiJson.filter_education) {
      mustConditions.push({ "key": "education", "match": { "text": aiJson.filter_education } });
    }
    if (aiJson.filter_experience) {
      mustConditions.push({ "key": "text", "match": { "text": aiJson.filter_experience } });
    }
    if (aiJson.filter_skills && Array.isArray(aiJson.filter_skills)) {
      aiJson.filter_skills.forEach(skill => {
        mustConditions.push({ "key": "text", "match": { "text": skill } });
      });
    }

    // 3. CẤU HÌNH BODY REQUEST

    let body = {

      "vector": $json.query_vector,

      "limit": $json.limit, // Tăng limit lên một chút vì lọc nhiều điều kiện

      "with_payload": true,

      "score_threshold": $json.score_threshold

    };

    // 4. ÁP DỤNG FILTER
    if (mustConditions.length > 0) {
      body.filter = {
        "must": mustConditions
      };

      // Hạ threshold nếu đã filter đích danh tên
      if (aiJson.filter_candidate_name) {
        body.score_threshold = 0;
      } else if (aiJson.filter_skills) {
        body.score_threshold = 0.25;
      }
    }

    return JSON.stringify(body);
  })()
}}

